import{_ as e,o as a,c as t,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"猩红之斧","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/白刃类/猩红之斧.md","filePath":"4.资源分区/6.技艺及称号/武技类/白刃类/猩红之斧.md"}'),s={name:"4.资源分区/6.技艺及称号/武技类/白刃类/猩红之斧.md"};function d(o,b,l,_,i,c){return a(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"猩红之斧",tabindex:"-1"},[p("猩红之斧 "),r("a",{class:"header-anchor",href:"#猩红之斧","aria-label":'Permalink to "猩红之斧"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌036")])])],-1),n('<h1 id="猩红之斧-1" tabindex="-1">猩红之斧 <a class="header-anchor" href="#猩红之斧-1" aria-label="Permalink to &quot;猩红之斧&quot;">​</a></h1><p>猩红之斧<br> 特异本质<br> 称号<br> D+500<br> 血液在体内循环，肢体在肌肉牵动下活动<br> 心脏不停的泵动，骨头撑起了整个的躯体<br> 所以——<br> 瞄准肌腱！撕裂胸膛！<br> 凿穿皮肉！砍断骨头！<br> 让血液自心脏射向天空！<br> 让灼热的鲜血！留在我的斧上！挥洒在你我的身上！<br> 你将成为一名信奉猩红血液的无名斧战士<br> 更大的创伤，更多的鲜血，更多的死亡<br> 这些让你为之狂热<br> 【猩红之斧】<br> 斧上的红色，不是颜料，而是鲜血。<br> 此刻开始，无论你所持有的斧头形象如何，你造成伤害后的血迹都将留在上面，并且永远鲜艳。<br> 而这些受害者的鲜血，又将为你所用，为你带来更多的鲜血——你以斧类武器造成的攻击将有一点严重转化为韧性伤害。<br> 【血腥祝福】<br> 嗅到了吗？<br> 这股血腥的气息？<br> 无论这是你的，或我的<br> 消耗一个迅捷动作对自己造成一道伤口，视为对自己造成2点严重伤害，流出的不是鲜血，而是血红色的雾气<br> 这些逸散的血腥气息将附着在你的武器上，本场景中，你的斧类武器上将获得攻击上的3点士气加值。</p><p>血腥投斧<br> D+500<br> 不可逃离，不被允许<br> 对于即将逃脱的猎物，那就投出手中的利斧<br> 你将能以【斧】专业代替【投掷】专业进行投掷，随后——不准逃！受到投掷攻击伤害的目标将以强韧豁免，若豁免失败将受到鲜血束缚，这是一个持续一轮的D级的困难地形效果，在判断来源时视为D级创伤来源。<br> 投掷出去以后，记得把斧头捡回来。</p><p>【嗜血挥击】<br> C+1000<br> 听呐，听呐<br> 你的心脏在轰鸣<br> 那种勃勃生机<br> 那种生存的本意<br> 而我，将断绝你的生机<br> 使用一个标准动作，对一个攻击范围内的目标进行一次血腥挥击<br> 本次攻击造成挥砍伤害，随后，目标需以一个强韧豁免，若豁免失败，则本次攻击将附带一个B级创伤来源的重伤效果，并且，无论是否重伤，本次攻击都将造成一点不可豁免的流血点数。</p><p>【血腥之铠】<br> C+1000<br> 强者胜，弱者败<br> 败者沦为食粮，随后又挥斧向更强<br> 所有杀不死你的，都能令你变得更强。<br> 现在开始，猩红血液将为血腥之斧赋予恩赐，同时占据你的1点意志池。<br> 猩红之斧将变得能够吸取血液，你的每一次攻击若造成至少3点实际伤害，都能使它汲取血液并反哺使用者恢复1点生命，这视为1点【吸血】。<br> 同时现在，猩红之斧上的鲜血将能转移到你的防具之上，为你构筑一层猩红铠甲，他将包裹你原本的防具，为其镀上一层血腥的光芒——你获得1点【活体护甲】<br> 在血腥之铠状态下，你将变得无需休息。<br> 现在开始，你的每一次战胜更强者，都能将其血液化为食粮，那是铸就你不破之铠的基石，每次影片中，当你第一次战胜高一级敌人后，猩红之斧将吸取对方的血液，在影片结束后，你额外获得一点活性护甲。</p><p>【血腥之手】<br> C+1000<br> 猩红已至！<br> 我将为此，献上鲜血！<br> 使用一个标准动作，对自身造成一点严重伤害，若你完好生命值为满，是你对自己划开一道伤口使血液流出，若你完好生命值不为满，则是你的伤口中流出鲜血，附着在你的斧头上<br> 随后进行一次近战攻击，手中的斧头将挥出腥风，你斩出五道猩红的斧影，这五道斧影将形成血腥之手将对身前6米扇形范围内所有敌人造成挥砍伤害，这次攻击额外具有1dp能量加值。</p><p>【生血烈阳】<br> B+2000<br> 太阳！太阳！太阳！<br> 那一轮血之日！<br> 那一轮毁灭之烈阳！<br> 那是猩红的独眼，那是血液的归巢！<br> 特殊的，本技艺需要你处于无完好状态时才可使用，因为你的每一滴流逝的鲜血，都将在你的头顶汇聚为一颗血液之球，它无法被破坏，无法被驱散，直到你的【仪式】完成——<br> 使用一个标准动作，血之球将如巨人之眼一般睁开，环视一圈，随后立刻变为一把猩红巨斧，对以你为中心周围15m圆形范围内的敌方目标造成一次不附带技艺的斩击，最后回到你的头顶。<br> 同时，在你回合结束时，生血烈焰将重复一次以上行为，持续一场景，直到战斗结束或你的生命值再次拥有完好为止。<br> 并且，所有受到生血烈焰伤害的目标将针对那次攻击进行一次强韧豁免，dc为攻击的伤害，若豁免失败，则你获得该目标持续一场景的【真实视觉】。</p><p>【血海冥河】<br> A+4000<br> 血啊，它已经来了<br> 万古至今，创伤之鲜血<br> 它们从未离去，它们从未干涸<br> 于此地，于此时<br> 我唤它显现<br> 并为它奉上此时之血<br> 血海冥河——处刑之仪<br> 使用一个标准动作，你将手中的斧子举起，随后向身前斩去，一道巨大的伤痕自你的身前斩开，大量的鲜血将喷溅而出，它们迅速流淌，以你为中心向外扩散，直到抵达你的敏感范围极限。<br> 此时，你的身前将出现一个模糊的血影，同时，在你的敏感范围内的所有敌方目标身边将出现一道身形与你相似的持斧血影。<br> 斧刃轻巧的划过目标的脖颈，所有血影也将同时对身前的目标发动攻击——<br> 所有受到伤害的目标将进行一次强韧豁免<br> 若失败，则血影将以最残忍的方式立刻对其处刑，使其鲜血融入血海中，这视为一个A级的创伤来源的【即死】效果。<br> 而幸存者将额外进行一次意志豁免，若失败，则一丝微不可查的血气将入侵他们，目标将遭受一个无支线级的创伤来源信息共享效果与无支线级的创伤来源思维暗示效果，他们的视网膜中将开始播放血影眼中其他人的死状，并且将不自觉的不断回想，持续一轮。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',10)])])}const m=e(s,[["render",d]]);export{f as __pageData,m as default};
